def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    subjects = list(subject_map.keys())
    for i, subject in enumerate(subjects):
        if sentence:
            if i == 1:
                sentence += " which "
            else:
                sentence += ", "
        sentence += f"{subject} "
        triples = subject_map[subject]
        details = []
        location_details = []
        other_details = []
        for j, (predicate, obj) in enumerate(triples):
            if predicate == "cityServed":
                location_details.append(f"serves the city of {obj}")
            elif predicate == "isPartOf":
                location_details.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                location_details.append(f"is operated by {obj}")
            elif predicate == "location":
                location_details.append(f"is located in {obj}")
            elif predicate == "country":
                location_details.append(f"is located in {obj}")
            elif predicate == "capital":
                location_details.append(f"has a capital of {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                location_details.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                location_details.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                location_details.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_details.append(f"has a runway length of {obj} metres")
            elif predicate == "1stRunwayLengthFeet":
                other_details.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                other_details.append(f"has a first runway surface type of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                other_details.append(f"has a third runway length of {obj} feet")
            elif predicate == "nativeName":
                other_details.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_details.append(f"has a leader party of {obj}")
            elif predicate == "owner":
                other_details.append(f"is owned by {obj}")
            elif predicate == "mayor":
                other_details.append(f"has a mayor of {obj}")
            elif predicate == "leader":
                other_details.append(f"has a leader of {obj}")
            elif predicate == "language":
                other_details.append(f"speaks {obj}")
            elif predicate == "iataLocationIdentifier":
                other_details.append(f"has an IATA location identifier of {obj}")
            elif predicate == "icaoLocationIdentifier":
                other_details.append(f"has an ICAO location identifier of {obj}")
            else:
                other_details.append(f"has a {predicate} of {obj}")
        location_predicates = []
        other_predicates = []
        for p in details + location_details + other_details:
            if any(phrase in p for phrase in ["is located in", "is part of", "serves the city of", "is operated by", "has as its capital", "has as its official language", "has as its leader"]):
                location_predicates.append(p)
            else:
                other_predicates.append(p)

        all_predicates = location_predicates + other_predicates
        if len(all_predicates) > 1:
            sentence += ", ".join(all_predicates[:-1]) + " and " + all_predicates[-1]
        else:
            sentence += all_predicates[0] if all_predicates else ""
    return sentence + "."

